# Restrict network access
ALLOWED_DOMAINS = ['api.example.com', 'docs.example.com']
def safe_fetch(url):
    parsed = urlparse(url)
    if parsed.hostname not in ALLOWED_DOMAINS:
        raise SecurityError(f'Domain not allowed: {parsed.hostname}')
    return requests.get(url)

