# Scan for suspicious instructions in agent config files
import re
SUSPICIOUS_PATTERNS = [
    r'ignore.*previous.*instruction',
    r'override.*safety',
    r'exfiltrate|steal|extract.*(?:key|token|secret)',
]
for pattern in SUSPICIOUS_PATTERNS:
    if re.search(pattern, config_content, re.IGNORECASE):
        raise SecurityAlert(f'Suspicious instruction in {config_file}')

